import{St as e,ct as t,lt as n,q as r}from"./chunks/framework.CmioJCXl.js";var i=JSON.parse(`{"title":"专业课","description":"介绍华南理工大学的学院和专业，也提供相关专业学习指南的跳转地址","frontmatter":{"lang":"zh-CN","title":"专业课","description":"介绍华南理工大学的学院和专业，也提供相关专业学习指南的跳转地址"},"headers":[],"relativePath":"en/learn/curricular/majors.md","filePath":"en/learn/curricular/majors.md","lastUpdated":1784220723000}`),a={name:`en/learn/curricular/majors.md`};function o(r,i,a,o,s,c){return e(),t(`div`,null,[...i[0]||=[n(`<h1 id="专业课" tabindex="-1">专业课 <a class="header-anchor" href="#专业课" aria-label="Permalink to “专业课”">​</a></h1><p>介绍华南理工大学的学院和专业，也提供相关专业学习指南的跳转地址（仅供参考）</p><p>TODO: 其他学院的专业学习攻略</p><h2 id="未来技术学院" tabindex="-1">未来技术学院 <a class="header-anchor" href="#未来技术学院" aria-label="Permalink to “未来技术学院”">​</a></h2><h3 id="未来技术学院课程攻略" tabindex="-1">未来技术学院课程攻略 <a class="header-anchor" href="#未来技术学院课程攻略" aria-label="Permalink to “未来技术学院课程攻略”">​</a></h3><p>未来技术学院（华南理工大学未来技术学院人工智能协会）的学长及其他贡献者创立了该仓库以共享和交流华工未院课程相关资源</p><p><a href="https://openfutech.github.io/SCUT-FT-Guide/" target="_blank" rel="noreferrer">华南理工未来技术学院课程攻略 - 网页链接</a></p><p><a href="https://github.com/OpenFuTech/SCUT-FT-Guide/" target="_blank" rel="noreferrer">GitHub 项目链接</a></p><p>（该地址国内/校园网络访问可能存在障碍）</p><h3 id="scut-cs-ai科研入门指南" tabindex="-1">SCUT cs/AI科研入门指南 <a class="header-anchor" href="#scut-cs-ai科研入门指南" aria-label="Permalink to “SCUT cs/AI科研入门指南”">​</a></h3><p>鉴于华南理工大学的人工智能专业及计算机等专业培养方案对科研能力几乎没有提升的弊端，<a href="https://github.com/oplisty" target="_blank" rel="noreferrer">Oplisty</a>联合了计算机专业及人工智能专业的几个同学，创建了此网站旨在为学弟学妹的科研入门提供便利，防止走弯路。</p><p><a href="https://github.com/oplisty/SCUT-AIdiy" target="_blank" rel="noreferrer">GitHub 项目地址</a></p><p><a href="https://lin-ze-pengsorganization.gitbook.io/aidiy/" target="_blank" rel="noreferrer">网页访问地址</a></p><h3 id="scuteee-华南理工电力电子类专业知识库" tabindex="-1">SCUTEEE 华南理工电力电子类专业知识库 <a class="header-anchor" href="#scuteee-华南理工电力电子类专业知识库" aria-label="Permalink to “SCUTEEE 华南理工电力电子类专业知识库”">​</a></h3><p>SCUTEEE 类似于 IEEE，SCUT 是华南理工大学（South China University of Technology），EEE 则是电气与电子工程师（Electrical and Electronics Engineers）。SCUTEEE 关注的领域与 IEEE 类似，集中于电气、电子、微电子、计算机、自动化等领域。这些领域存在大量交叉，许多课程大体上是相同的，可以相互借鉴。</p><p><a href="https://github.com/scuteee/scuteee" target="_blank" rel="noreferrer">Github 项目地址</a></p><p><a href="https://scuteee.com/" target="_blank" rel="noreferrer">网页访问地址</a></p>`,17)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};